pub fn parse_user(input: &str) -> Result<User, ParseUserError> {
    let mut parts = input.split(',');

    let id_text = parts.next().ok_or(ParseUserError::MissingId)?;
    let name = parts.next().ok_or(ParseUserError::MissingName)?;
    let email = parts.next().ok_or(ParseUserError::MissingEmail)?;

    let id = id_text
        .parse::<u64>()
        .map_err(|_| ParseUserError::InvalidId)?;

    Ok(User {
        id,
        name: name.to_owned(),
        email: email.to_owned(),
    })
}

